#!/usr/bin/env node
const { io } = require("socket.io-client");
const { spawn } = require("child_process");
const net = require("net");
const fs = require("fs");
const os = require("os");
const SERVER = process.env.AHD_SERVER || "ws://localhost:3000/ws";
const API_KEY = process.env.AHD_DEVICE_API_KEY || "";
const IPC_PATH = "/tmp/ahd-mpv.sock";
function cpuSerial() { try { const txt = fs.readFileSync("/proc/cpuinfo", "utf8"); const m = txt.match(/Serial\s*:\s*([0-9a-fA-F]+)/); if (m) return m[1]; } catch {} return (process.env.AHD_DEVICE_SERIAL || `dev-${os.hostname()}-${process.pid}`); }
const serial = cpuSerial();
const hostname = os.hostname();
let mpv;
function ensureMpv() { if (mpv && !mpv.killed) return; try { fs.unlinkSync(IPC_PATH); } catch {} mpv = spawn("mpv", ["--idle=yes","--no-video","--no-terminal","--volume=80","--input-ipc-server="+IPC_PATH,"--cache=yes","--cache-secs=2","--audio-client-name=ahd-radio-dj"], { stdio: "ignore" }); mpv.on("exit", function() { setTimeout(ensureMpv, 1000); }); }
function mpvCommand(cmd) { return new Promise(function(resolve) { const c = net.createConnection(IPC_PATH, function() { c.write(JSON.stringify({ command: cmd }) + "\n"); setTimeout(function() { c.end(); resolve(); }, 50); }); c.on("error", function() { resolve(); }); }); }
let currentUrl = null;
async function play(url) { currentUrl = url; await mpvCommand(["loadfile", url, "replace"]); }
async function stop() { currentUrl = null; await mpvCommand(["stop"]); }
async function pause(v) { await mpvCommand(["set_property", "pause", v]); }
async function setVolume(v) { await mpvCommand(["set_property", "volume", Math.max(0, Math.min(100, v))]); }
async function identify() { const tone = spawn("mpv", ["--no-video","--no-terminal","av://lavfi/sine=f=880:d=1.5"], { stdio: "ignore" }); await new Promise(function(r) { tone.on("exit", r); }); if (currentUrl) await play(currentUrl); }
let announceProc = null;
let savedVolume = null;
async function announceStart(url, vol) { if (announceProc && !announceProc.killed) { try { announceProc.kill("SIGTERM"); } catch {} } savedVolume = (savedVolume === null) ? 80 : savedVolume; await setVolume(10); announceProc = spawn("mpv", ["--no-video","--no-terminal","--volume="+vol,"--cache=yes","--cache-secs=1",url], { stdio: "ignore" }); announceProc.on("exit", function() { announceProc = null; }); }
async function announceStop() { if (announceProc && !announceProc.killed) { try { announceProc.kill("SIGTERM"); } catch {} announceProc = null; } if (savedVolume !== null) { await setVolume(savedVolume); savedVolume = null; } }
ensureMpv();
const socket = io(SERVER.replace(/\/ws$/, ""), { path: "/ws", transports: ["websocket"], reconnection: true, extraHeaders: { Authorization: "Bearer " + API_KEY, "X-Device-Serial": serial, "X-Device-Hostname": hostname } });
socket.on("connect", function() { console.log("[ahd-pi] connected as " + hostname + " (" + serial + ")"); setInterval(function() { socket.emit("heartbeat"); }, 30000); });
socket.on("connect_error", function(e) { console.error("[ahd-pi] connect_error:", e.message); });
socket.on("disconnect", function(r) { console.warn("[ahd-pi] disconnected:", r); });
socket.on("config", function(cfg) { console.log("[ahd-pi] config:", cfg); if (cfg && cfg.streamUrl) { play(cfg.streamUrl); setVolume(cfg.volume || 80); savedVolume = cfg.volume || 80; } else { stop(); } });
socket.on("command", async function(cmd) { console.log("[ahd-pi] cmd:", cmd); if (cmd.type === "play") await play(cmd.url); else if (cmd.type === "stop") await stop(); else if (cmd.type === "pause") await pause(true); else if (cmd.type === "resume") await pause(false); else if (cmd.type === "volume") { savedVolume = cmd.value; if (!announceProc) await setVolume(cmd.value); } else if (cmd.type === "identify") await identify(); else if (cmd.type === "announce-start") await announceStart(cmd.url, cmd.volume); else if (cmd.type === "announce-stop") await announceStop(); socket.emit("status", { type: cmd.type, ts: Date.now() }); });
